var e=JSON.parse(`[{"id":"idx_0","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰","JPN":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n付録: 対象者観察","ENG":"CCN No. CSM002M000755-09\\n<color=#ffd34c>Class 3 Subject</color> Access Approval Documents\\nAppendix: Subject Surveillance","TWN":"(TWN)CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"████\xA0대행.\xA0관찰대상\xA0새디어스 모건에 관한 사안으로 연락드렸습니다.","JPN":"████ 代行。観察対象タデウス・モーガンに関する事案でご連絡致しました。","ENG":"████ Executive Officer. Contacting you regarding the surveillance target, Thaddeus Morgan.","TWN":"(TWN)████\xA0대행.\xA0관찰대상\xA0새디어스 모건에 관한 사안으로 연락드렸습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_2","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"나는 자네의 신속하고 정확한 보고에 항상 감사하고 있다네.","JPN":"私は君の迅速して正確な報告に常に感謝しているよ。","ENG":"I am always grateful for your swift and accurate reports.","TWN":"(TWN)나는 자네의 신속하고 정확한 보고에 항상 감사하고 있다네."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_3","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 일전에 전송해 준 자료는 아쉬운 점이 있더군.\\n한 번도 아니고 두 번이나 발각되다니.","JPN":"しかし先日に転送してくれた資料は惜しい点があっていたよ。\\n一回もなくて二回もばれるなんて。","ENG":"However, the data you transmitted previously had some questionable points.\\nTo think it was flagged not once, but twice.","TWN":"(TWN)하지만 일전에 전송해 준 자료는 아쉬운 점이 있더군.\\n한 번도 아니고 두 번이나 발각되다니."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_4","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 부분에 대해서는 죄송하다고 생각합니다.","JPN":"その部分に対しては申し訳ないと思います。","ENG":"I apologize for that aspect.","TWN":"(TWN)그 부분에 대해서는 죄송하다고 생각합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_5","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 실무에 투입할 D급 카운터라도 정보과에 배치해 주셨다면 결과가 조금 달라지지 않았을까요.","JPN":"しかし実務に投入するD級カウンターでも情報科に配置してくれたら結果が少し変わらなかったんでしょうか。","ENG":"But if you had assigned this to even a Class D Counter in the Intelligence Division, wouldn't the results have been somewhat different?","TWN":"(TWN)하지만 실무에 투입할 D급 카운터라도 정보과에 배치해 주셨다면 결과가 조금 달라지지 않았을까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_6","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네는 여기만 오면 예산이란 놈을 너무 우습게 여긴단 말이지.","JPN":"君はここだけ来れば予算というものをとても可笑しくここは束巻きだ。","ENG":"You come here and only complain about the budget.","TWN":"(TWN)자네는 여기만 오면 예산이란 놈을 너무 우습게 여긴단 말이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_7","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어쨌든, 조사는 순조로운가?","JPN":"とにかく、調査は順調なのか?","ENG":"Anyway, is the investigation proceeding smoothly?","TWN":"(TWN)어쨌든, 조사는 순조로운가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_8","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"네. 10년 전 민간에 공개된 SIS 기밀 자료에서 단서를 포착했습니다.","JPN":"はい。10年前民間に公開されたSIS機密資料で手がかりを捕捉しました。","ENG":"Yes. We captured a lead from SIS classified documents released to the public a decade ago.","TWN":"(TWN)네. 10년 전 민간에 공개된 SIS 기밀 자료에서 단서를 포착했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_9","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"더미일 가능성은?","JPN":"ダミーである可能聖恩?","ENG":"Probability of it being a dummy?","TWN":"(TWN)더미일 가능성은?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_10","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"구 관리국 자료와 대조한 결과, 위조되었을 확률은 2.37%입니다.","JPN":"旧管理局資料と対照した結果、偽造された確率は2.37%です。","ENG":"Results of cross-referencing with old Administration Bureau records indicate a 2.37% probability of forgery.","TWN":"(TWN)구 관리국 자료와 대조한 결과, 위조되었을 확률은 2.37%입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_11","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"적당히 걸러 들으라는 뜻이군. 계속해 보게.","JPN":"適当にかけにききなさいという意味だね。続けてみなさい。","ENG":"So you mean to take it with a grain of salt. Continue.","TWN":"(TWN)적당히 걸러 들으라는 뜻이군. 계속해 보게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_12","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"예상하셨겠지만, 새디어스 모건이라는 신분은 SIS를 통해 가공된 것입니다.","JPN":"予想したが、タデウス・モーガンという身分はSISを通じて加工されたことです。","ENG":"As you may have guessed, the identity of Thaddeus Morgan was fabricated through SIS.","TWN":"(TWN)예상하셨겠지만, 새디어스 모건이라는 신분은 SIS를 통해 가공된 것입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_13","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"20세기 말에 SIS는 변심한 적성국 요원들의 신변 보호를 위해 대대적인 신분 정화 작업을 실시한 적이 있습니다.","JPN":"20世紀末にSISは心変わりした適性国要員の身近保護のために大々的な身分浄化作業を実施したことがあります。","ENG":"At the end of the 20th century, SIS conducted large-scale identity cleansing operations to protect defecting hostile nation agents.","TWN":"(TWN)20세기 말에 SIS는 변심한 적성국 요원들의 신변 보호를 위해 대대적인 신분 정화 작업을 실시한 적이 있습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_14","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"현재 남아 있는 새디어스 모건의 프로필은 이 당시 제작했다고 추측됩니다.","JPN":"現在残っているタデウス・モーガンのプロフィールはこの当時製作したと推測されます。","ENG":"The current profile of Thaddeus Morgan is estimated to have been created during that time.","TWN":"(TWN)현재 남아 있는 새디어스 모건의 프로필은 이 당시 제작했다고 추측됩니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_15","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이전 행적을 확인하려면 SIS에 피로연이라도 제공해 줘야 한다는 건가?","JPN":"以前行跡を確認しようとすればSISに披露宴でも提供してくれなければならないという濃いか?","ENG":"Does that mean we need to provide SIS with even a blood relative to verify previous records?","TWN":"(TWN)이전 행적을 확인하려면 SIS에 피로연이라도 제공해 줘야 한다는 건가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_16","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"신분 정화 작업을 진행한 책임자는 5년 전 사망한 것으로 확인했습니다.","JPN":"身分浄化作業を進行した責任者は5年前死亡したことで確認しました。","ENG":"The person responsible for conducting the identity cleansing operation was confirmed to have died five years ago.","TWN":"(TWN)신분 정화 작업을 진행한 책임자는 5년 전 사망한 것으로 확인했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_17","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"사인은 측두부 총상, 동거인에 의해 자택에서 발견됐으며 자살로 결론지어졌더군요.","JPN":"サインは側豆腐銃創、同居人によって自宅で発見されて自殺で結論付けられましたよ。","ENG":"Cause of death was a temporal gunshot wound, discovered at his residence by his cohabitant, and ruled a suicide.","TWN":"(TWN)사인은 측두부 총상, 동거인에 의해 자택에서 발견됐으며 자살로 결론지어졌더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_18","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"사건을 수사한 경찰도 처음에는 타살을 의심했지만, 외부인의 개입을 증명할 증거가 전무했다더군요.","JPN":"事件を捜査した警察も初めには他殺を疑ったが、部外者の介入を証明する証拠が全くなかったと言う。","ENG":"The police who investigated the case initially suspected homicide, but there was no evidence to prove outsider involvement.","TWN":"(TWN)사건을 수사한 경찰도 처음에는 타살을 의심했지만, 외부인의 개입을 증명할 증거가 전무했다더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_19","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"물론, 타인의 약점을 교묘하게 활용하는 타입의 범인이라면 자살을 종용했을지도 모르지만요.","JPN":"もちろん、他人の弱点を巧みに活用するタイプの犯人なら自殺を慫慂したかも知れないけれども。","ENG":"Of course, if the perpetrator is the type to cleverly exploit others' weaknesses, they might have driven him to suicide.","TWN":"(TWN)물론, 타인의 약점을 교묘하게 활용하는 타입의 범인이라면 자살을 종용했을지도 모르지만요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_20","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이번 관찰대상이 범인이라고 생각하는 건가?","JPN":"今回観察対象が犯人と思うのか?","ENG":"Do you think this surveillance target is the perpetrator?","TWN":"(TWN)이번 관찰대상이 범인이라고 생각하는 건가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_21","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"신분 정화 작업의 수혜를 입은 인원 대부분은 민간인으로 지내고 있습니다. 현장에 남아 있는 인원부터 의심할 수밖에요.","JPN":"身分浄化作業の受益を着た人員大部分は民間人で過ごしています。現場に残っている人員から疑う数しかです。","ENG":"Most personnel who benefited from the identity cleansing operation are living as civilians. We have no choice but to suspect those remaining on the scene.","TWN":"(TWN)신분 정화 작업의 수혜를 입은 인원 대부분은 민간인으로 지내고 있습니다. 현장에 남아 있는 인원부터 의심할 수밖에요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_22","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"내가 보기엔 동기가 부족하군.\\n좀 더 납득할 만한 근거를 제시해 보게.","JPN":"私が見るには同期が不足であるね。\\nもう少し納得するに値する根拠を提示してみなさい。","ENG":"In my view, the motive is insufficient.\\nPresent some more convincing evidence.","TWN":"(TWN)내가 보기엔 동기가 부족하군.\\n좀 더 납득할 만한 근거를 제시해 보게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_23","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"조사를 속행하란 지시로 이해하겠습니다.","JPN":"調査を続行するという指示で理解します。","ENG":"I understand this as an order to continue the investigation.","TWN":"(TWN)조사를 속행하란 지시로 이해하겠습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_24","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"물론일세. 하지만 현지 요원들은 투입하지 말고.\\n내 다른 방안을 준비해 두지.","JPN":"もちろんだよ。しかし現地要員は投入せずに。\\n出して違う方案を準備しておく。","ENG":"Of course. But do not deploy local agents.\\nI have prepared another measure.","TWN":"(TWN)물론일세. 하지만 현지 요원들은 투입하지 말고.\\n내 다른 방안을 준비해 두지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_25","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 배려에 감사드립니다.","JPN":"はい。配慮に感謝いたします。","ENG":"Yes. Thank you for your consideration.","TWN":"(TWN)네. 배려에 감사드립니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};